using BuildingBlocks.Endpoints;using BuildingBlocks.Modules;using BuildingBlocks.Persistence;using DashboardCharts.Domain;using DashboardCharts.Persistence;using Microsoft.AspNetCore.Routing;using Microsoft.Extensions.Configuration;using Microsoft.Extensions.DependencyInjection;namespace DashboardCharts;/** <summary>Dashboard module.</summary> */ public sealed class DashboardChartsModule:IModule{/** <inheritdoc/> */ public string Name=>"DashboardCharts";/** <inheritdoc/> */ public void Register(IServiceCollection s,IConfiguration c){ArgumentNullException.ThrowIfNull(s);ArgumentNullException.ThrowIfNull(c);s.AddModuleDbContext<DashboardChartsDbContext>(c,Name,DashboardChartsDbContext.Schema);s.AddScoped<IChartDefinitionRepository,ChartDefinitionRepository>();}/** <inheritdoc/> */ public void MapEndpoints(IEndpointRouteBuilder e)=>e.MapEndpointsFromAssembly(typeof(DashboardChartsModule).Assembly);}
